import React, { type FunctionComponent } from 'react';
import type {IKitsContainer} from "@lmb/kitsconcerto-types";
import {Flex, Text} from "../../../../";

interface IAddonsProps {
    leftAddon?: IKitsContainer["leftAddon"];
    rightAddon?: IKitsContainer["rightAddon"];
    children: IKitsContainer["children"];
    additionalClassName?:string;
}

const Addons: FunctionComponent<IAddonsProps> = ({rightAddon, leftAddon, children, additionalClassName}) => {

    const renderAddon = (addon: IKitsContainer["leftAddon"] | IKitsContainer["rightAddon"]) => {
        if (!addon) return null;

        if (typeof addon === "string") {
            return (
                <Text fontSize={14}>
                    {addon}
                </Text>
            );
        }

        if (React.isValidElement(addon)) {
            return addon;
        }

        return null;
    };

    const mergedClassName = additionalClassName ?? "";

  return (
      <Flex
          flexDirection="row"
          w="full"
          alignItems="stretch"
          className={mergedClassName}
      >
          {leftAddon && (
              <Flex
                  px={8}
                  py={6}
                  alignItems="center"
                  justifyContent="center"
                  bgColor="var(--surface-200)"
                  borderTopLeftRadius={6}
                  borderBottomLeftRadius={6}
              >
                  {renderAddon(leftAddon)}
              </Flex>
          )}

          <Flex flex={1}>{children}</Flex>

          {rightAddon && (
              <Flex
                  px={8}
                  py={6}
                  alignItems="center"
                  justifyContent="center"
                  bgColor="var(--surface-200)"
                  borderTopRightRadius={6}
                  borderBottomRightRadius={6}
              >
                  {renderAddon(rightAddon)}
              </Flex>
          )}
      </Flex>
  );
};

export default Addons;
